const resp = $input.first().json;
const campaigns = resp?.data || [];

if (campaigns.length === 0) {
  return []; // 활성 캠페인 없으면 종료
}

const alerts = [];
for (const c of campaigns) {
  const dailyBudget = parseInt(c.daily_budget || '0');
  const budgetRemaining = parseInt(c.budget_remaining || '0');
  const todaySpend = parseFloat(c.insights?.data?.[0]?.spend || '0');

  if (dailyBudget === 0) continue;

  const spentPercent = dailyBudget > 0 ? (todaySpend / (dailyBudget / 100)) : 0;
  const remainPercent = dailyBudget > 0 ? (budgetRemaining / dailyBudget * 100) : 100;

  // 경보 조건: 오늘 소진 80% 이상 OR 남은 예산 20% 미만
  if (spentPercent >= 80 || remainPercent < 20) {
    alerts.push({
      name: c.name,
      dailyBudget,
      todaySpend: Math.round(todaySpend),
      budgetRemaining,
      spentPercent: Math.round(spentPercent),
      remainPercent: Math.round(remainPercent),
      status: spentPercent >= 100 ? 'DEPLETED' : 'WARNING'
    });
  }
}

if (alerts.length === 0) {
  return []; // 경보 없으면 종료
}

let msg = '🚨 *Meta Ads 예산 경보*\n\n';
for (const a of alerts) {
  const icon = a.status === 'DEPLETED' ? '🔴' : '🟡';
  msg += icon + ' *' + a.name + '*\n';
  msg += '  일예산: ' + a.dailyBudget.toLocaleString() + '원\n';
  msg += '  오늘 소진: ' + a.todaySpend.toLocaleString() + '원 (' + a.spentPercent + '%)\n';
  msg += '  잔여 예산: ' + a.budgetRemaining.toLocaleString() + '원\n\n';
}
msg += '💡 예산 조정이 필요하면 지호님께 확인하세요.';

return [{ json: { message: msg, alertCount: alerts.length } }];
